SELECT COUNT(1)
FROM md_role mr
LEFT JOIN md_tenant_role  mtr ON mr.id = mtr.role_id
WHERE mtr.tenant_id = #{tenantId}
AND mtr.app_id = #{appId}
AND mr.name = #{roleName}

SELECT COUNT(1)
FROM md_role mr
LEFT JOIN md_tenant_role  mtr ON mr.id = mtr.role_id
WHERE mtr.tenant_id = #{tenantId}
AND mtr.role_id != #{roleId}
AND mtr.app_id = #{appId}
AND mr.name = #{roleName}
